// 7-Segment Counter — button increments 0-9, wraps to 0
// Common-cathode display
// Segments: a=2, b=3, c=4, d=5, e=6, f=7, g=8
// Button: D10 (INPUT_PULLUP)

const int SEG_A = 2;
const int SEG_B = 3;
const int SEG_C = 4;
const int SEG_D = 5;
const int SEG_E = 6;
const int SEG_F = 7;
const int SEG_G = 8;
const int BTN_PIN = 10;

int counter = 0;
int lastBtnState = HIGH;

void showDigit(int n) {
  // a b c d e f g
  if (n == 0) { digitalWrite(SEG_A,HIGH); digitalWrite(SEG_B,HIGH); digitalWrite(SEG_C,HIGH); digitalWrite(SEG_D,HIGH); digitalWrite(SEG_E,HIGH); digitalWrite(SEG_F,HIGH); digitalWrite(SEG_G,LOW);  }
  else if (n == 1) { digitalWrite(SEG_A,LOW);  digitalWrite(SEG_B,HIGH); digitalWrite(SEG_C,HIGH); digitalWrite(SEG_D,LOW);  digitalWrite(SEG_E,LOW);  digitalWrite(SEG_F,LOW);  digitalWrite(SEG_G,LOW);  }
  else if (n == 2) { digitalWrite(SEG_A,HIGH); digitalWrite(SEG_B,HIGH); digitalWrite(SEG_C,LOW);  digitalWrite(SEG_D,HIGH); digitalWrite(SEG_E,HIGH); digitalWrite(SEG_F,LOW);  digitalWrite(SEG_G,HIGH); }
  else if (n == 3) { digitalWrite(SEG_A,HIGH); digitalWrite(SEG_B,HIGH); digitalWrite(SEG_C,HIGH); digitalWrite(SEG_D,HIGH); digitalWrite(SEG_E,LOW);  digitalWrite(SEG_F,LOW);  digitalWrite(SEG_G,HIGH); }
  else if (n == 4) { digitalWrite(SEG_A,LOW);  digitalWrite(SEG_B,HIGH); digitalWrite(SEG_C,HIGH); digitalWrite(SEG_D,LOW);  digitalWrite(SEG_E,LOW);  digitalWrite(SEG_F,HIGH); digitalWrite(SEG_G,HIGH); }
  else if (n == 5) { digitalWrite(SEG_A,HIGH); digitalWrite(SEG_B,LOW);  digitalWrite(SEG_C,HIGH); digitalWrite(SEG_D,HIGH); digitalWrite(SEG_E,LOW);  digitalWrite(SEG_F,HIGH); digitalWrite(SEG_G,HIGH); }
  else if (n == 6) { digitalWrite(SEG_A,HIGH); digitalWrite(SEG_B,LOW);  digitalWrite(SEG_C,HIGH); digitalWrite(SEG_D,HIGH); digitalWrite(SEG_E,HIGH); digitalWrite(SEG_F,HIGH); digitalWrite(SEG_G,HIGH); }
  else if (n == 7) { digitalWrite(SEG_A,HIGH); digitalWrite(SEG_B,HIGH); digitalWrite(SEG_C,HIGH); digitalWrite(SEG_D,LOW);  digitalWrite(SEG_E,LOW);  digitalWrite(SEG_F,LOW);  digitalWrite(SEG_G,LOW);  }
  else if (n == 8) { digitalWrite(SEG_A,HIGH); digitalWrite(SEG_B,HIGH); digitalWrite(SEG_C,HIGH); digitalWrite(SEG_D,HIGH); digitalWrite(SEG_E,HIGH); digitalWrite(SEG_F,HIGH); digitalWrite(SEG_G,HIGH); }
  else if (n == 9) { digitalWrite(SEG_A,HIGH); digitalWrite(SEG_B,HIGH); digitalWrite(SEG_C,HIGH); digitalWrite(SEG_D,HIGH); digitalWrite(SEG_E,LOW);  digitalWrite(SEG_F,HIGH); digitalWrite(SEG_G,HIGH); }
}

void setup() {
  pinMode(SEG_A, OUTPUT);
  pinMode(SEG_B, OUTPUT);
  pinMode(SEG_C, OUTPUT);
  pinMode(SEG_D, OUTPUT);
  pinMode(SEG_E, OUTPUT);
  pinMode(SEG_F, OUTPUT);
  pinMode(SEG_G, OUTPUT);
  pinMode(BTN_PIN, INPUT_PULLUP);
  showDigit(0);
}

void loop() {
  int btnState = digitalRead(BTN_PIN);
  if (btnState == LOW && lastBtnState == HIGH) {
    counter = counter + 1;
    if (counter > 9) {
      counter = 0;
    }
    showDigit(counter);
    delay(200);
  }
  lastBtnState = btnState;
}

